public static long solve(long[] prices, long[] strategy, long k) {
    int n = prices.length;
    long maxProfit = 0;

    // Calculate the original profit
    long originalProfit = 0;
    for (int i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }
    maxProfit = originalProfit;

    // Try all possible positions to modify the strategy
    for (int i = 0; i <= n - (int)k; i++) {
        // Create a copy of the strategy
        long[] modifiedStrategy = new long[n];
        System.arraycopy(strategy, 0, modifiedStrategy, 0, n);

        // Modify the strategy in the range [i, i + k - 1]
        int half = (int) (k / 2);
        for (int j = 0; j < k; j++) {
            if (j < half) {
                modifiedStrategy[i + j] = 0;
            } else {
                modifiedStrategy[i + j] = 1;
            }
        }

        // Calculate the profit with the modified strategy
        long currentProfit = 0;
        for (int m = 0; m < n; m++) {
            currentProfit += modifiedStrategy[m] * prices[m];
        }

        // Update the maximum profit
        if (currentProfit > maxProfit) {
            maxProfit = currentProfit;
        }
    }

    return maxProfit;
}
